{
  "verses": [
    {
      "n": 9,
      "column": "left",
      "text": "Jo tu KUNGS effi mans Patwerums/ tas Wiſſn-aug- ſtakajs irr teu par Gelbefchanu eezeelts.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Ne kahds Launums tew uſees/ un pee tawa Dſihwokta ne kahda Mohziba peestahfees.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Jo wiſch pawehlehs fa- veem Engeteem pahr tewi/ ka tee teivis patarga us wiſſeem tu- weem Zelteem.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Ka tee tevi us Rohfahm nefka/ ka tu tawu Kahju pee ne lahdu Akmini peedanſt.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Us Lauwahm un Ohdsehm tu miſſt/ un fasfahrdifi jaunus Lauwas un Puhkus.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Jo par to/ ka wiſch mannis grib/ tad es winnu is glahbfchu/ wiſch pasihſt mannii Wahrdu/ tapehz es winnu pa- augſtinaſchu.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Wiſch peefanz mannis/ an es winnu paklansſchu/ es pee winna eſmu eekſch Behdahm/ es gribru winnu isrant/ es grib- bu winnu pagohdinaht.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Es gribru winnu ar ilgu Dſihwoſchanu pa-ehdinaht/ es gribru winnam parahdiht man- nu Peſitſchanu.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Eena Dieetma Sweh- deena dseedaina.\nLabba Leeta irrt to KUNGS flaweht/ un tawam Wahrdam dseedahft/ tu Wiſſn- augſtakajs.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Nihta tawu Schehlastibu iſteikt/ un Nahtis tawu Pee- tizzibu.\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Us tahm defmits Stih- gahm un us Sohma-Stabu- lehm/ ar Spehlefchanu us Rohſti.\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Jo KUNGS/ tu eepreeze mann ar tawem Darbeem/ es gawileſchu pahr tawu Rohku Darrischanahm.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Ak KUNGS! zik leeli irr tawi Darbi/ tawas Dohmas irr tohti dsittas?\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Weens Trakkulis to neat- fiſſt/ un weens Gekkis to ne proht.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Tee Besdeewigee falto ka ta Sahle/ un wiſſi Launadar- ritaji feed/ teekams tee tohp fa- mattati muhſchigi muhſchain.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Bet tu effi tas Augsta- kajs/ tas KUNGS paleek muh- schigt.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Jo raugi/ tawi Eenaide- neeki ak KUNGS! raugi/ tawi Eenaidenekki ees bohja/ wiſſi Launadarritaji taps iſkaisiti.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Bet tu pa-augſtinaſi man- nu Raggu/ ka weena Weenrad- ſcha/ es eſmu ar jaunu Etji ap- leeſs.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Un manna Azz uſluh- foſs ar Libgſinibu mannuſ Waidneckus/ mannas Auſis dfir-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
